AFTER:
function createRegistryWithAllChannels() {
  const registry = new ChannelRegistry()
  const ALL_PLATFORMS: ChannelPlatform[] = ['whatsapp', 'slack', 'email', 'feishu', 'dingtalk']
  const channels = new Map<ChannelPlatform, ReturnType<typeof createStubChannel>>()

  for (const platform of ALL_PLATFORMS) {
    const channel = createStubChannel(platform)
    channels.set(platform, channel)
    registry.register(channel, { platform } as ChannelConfig)
  }

  return { registry, channels, platforms: ALL_PLATFORMS }
}

// In tests:
const { registry, channels, platforms } = createRegistryWithAllChannels()

WHY: Extracts ~7 lines of identical setup repeated 5 times into a single helper. The helper returns both Map and array-like access. Tests become more focused on assertions rather than setup.

